  1→import { NextRequest, NextResponse } from 'next/server';
  2→import { getStripe } from '@/lib/stripe';
  3→import { createClient } from '@supabase/supabase-js';
  4→import Stripe from 'stripe';
  5→import { PLANS } from '@/lib/constants';
  6→
  7→// Use service role client for webhook (no user session)
  8→function getAdminClient() {
  9→  return createClient(
 10→    process.env.NEXT_PUBLIC_SUPABASE_URL!,
 11→    process.env.SUPABASE_SERVICE_ROLE_KEY!
 12→  );
 13→}
