 15→export async function POST(request: NextRequest) {
 16→  const body = await request.text();
 17→  const signature = request.headers.get('stripe-signature');
 18→
 19→  if (!signature) {
 20→    return NextResponse.json({ error: 'No signature' }, { status: 400 });
 21→  }
 22→
 23→  let event: Stripe.Event;
 24→
 25→  try {
 26→    event = getStripe().webhooks.constructEvent(
 27→      body,
 28→      signature,
 29→      process.env.STRIPE_WEBHOOK_SECRET!
 30→    );
 31→  } catch (err) {
 32→    const message = err instanceof Error ? err.message : 'Webhook verification failed';
 33→    return NextResponse.json({ error: message }, { status: 400 });
 34→  }
 35→
 36→  const supabase = getAdminClient();
 37→
 38→  try {
 39→    switch (event.type) {
 40→      case 'checkout.session.completed': {
 41→        const session = event.data.object as Stripe.Checkout.Session;
 42→        const organizationId = session.metadata?.organizationId;
 43→        const subscriptionId = session.subscription as string;
 44→        const customerId = session.customer as string;
 45→
 46→        if (organizationId && subscriptionId) {
 47→          const subResponse = await getStripe().subscriptions.retrieve(subscriptionId);
 48→          // eslint-disable-next-line @typescript-eslint/no-explicit-any
 49→          const subscription = subResponse as any;
 50→          const priceId = subscription.items?.data?.[0]?.price?.id;
 51→
 52→          // Determine plan from price ID
 53→          let plan = 'pro';
 54→          for (const [key, config] of Object.entries(PLANS)) {
 55→            if (config.stripe_price_id_monthly === priceId || config.stripe_price_id_yearly === priceId) {
 56→              plan = key;
 57→              break;
 58→            }
 59→          }
 60→
 61→          const planLimits = PLANS[plan]?.limits;
 62→          const periodEnd = subscription.current_period_end
 63→            ? new Date(subscription.current_period_end * 1000).toISOString()
 64→            : null;
 65→
 66→          await supabase
 67→            .from('organizations')
 68→            .update({
 69→              stripe_customer_id: customerId,
 70→              stripe_subscription_id: subscriptionId,
 71→              plan,
 72→              plan_period_end: periodEnd,
 73→              doc_quota: planLimits?.documents_per_month === Infinity ? 999999 : planLimits?.documents_per_month || 10,
 74→              survey_quota: planLimits?.surveys === Infinity ? 999999 : planLimits?.surveys || 5,
 75→            })
 76→            .eq('id', organizationId);
 77→        }
 78→        break;
 79→      }
 80→
 81→      case 'customer.subscription.updated': {
 82→        // eslint-disable-next-line @typescript-eslint/no-explicit-any
 83→        const subscription = event.data.object as any;
 84→        const customerId = subscription.customer as string;
 85→
 86→        const { data: org } = await supabase
 87→          .from('organizations')
 88→          .select('id')
 89→          .eq('stripe_customer_id', customerId)
 90→          .single();
 91→
 92→        if (org && subscription.current_period_end) {
 93→          await supabase
 94→            .from('organizations')
 95→            .update({
 96→              plan_period_end: new Date(subscription.current_period_end * 1000).toISOString(),
 97→            })
 98→            .eq('id', org.id);
 99→        }
100→        break;
101→      }
102→
103→      case 'customer.subscription.deleted': {
104→        const subscription = event.data.object as Stripe.Subscription;
105→        const customerId = subscription.customer as string;
106→
107→        const { data: org } = await supabase
108→          .from('organizations')
109→          .select('id')
110→          .eq('stripe_customer_id', customerId)
111→          .single();
112→
113→        if (org) {
114→          const freeLimits = PLANS.free.limits;
115→          await supabase
116→            .from('organizations')
117→            .update({
118→              plan: 'free',
119→              stripe_subscription_id: null,
120→              plan_period_end: null,
121→              doc_quota: freeLimits.documents_per_month,
122→              survey_quota: freeLimits.surveys,
123→            })
124→            .eq('id', org.id);
125→        }
126→        break;
127→      }
128→    }
129→  } catch (error) {
130→    console.error('Webhook handler error:', error);
131→    return NextResponse.json({ error: 'Webhook handler failed' }, { status: 500 });
132→  }
133→
134→  return NextResponse.json({ received: true });
135→}
